<?php
declare(strict_types=1);

function resource_portal(string|int $value):array{$field=is_int($value)?'id':'slug';$q=db()->prepare("SELECT * FROM resource_portals WHERE $field=?");$q->execute([$value]);$r=$q->fetch();if(!$r){http_response_code(404);exit('Resource portal not found');}return $r;}
function resource_access(array $portal):?array{$token=(string)($_COOKIE['oc_resource_'.$portal['id']]??'');if(!preg_match('/^[a-f0-9]{64}$/',$token))return null;$q=db()->prepare('SELECT a.*,c.first_name,c.last_name,c.email FROM resource_access_sessions a JOIN contacts c ON c.id=a.contact_id WHERE a.portal_id=? AND a.access_token=? AND a.expires_at>NOW()');$q->execute([$portal['id'],$token]);$a=$q->fetch();if($a)db()->prepare('UPDATE resource_access_sessions SET last_seen_at=NOW() WHERE id=?')->execute([$a['id']]);return $a?:null;}
function resource_apply_tags(int $contactId,array $tagIds):void{$q=db()->prepare('INSERT IGNORE INTO contact_tags(contact_id,tag_id) VALUES(?,?)');foreach(array_unique(array_map('intval',$tagIds)) as $id)if($id)$q->execute([$contactId,$id]);}

if(preg_match('#^/resource-library/([a-z0-9_-]+)$#',$path,$m)){
 $portal=resource_portal($m[1]);if(!$portal['active']){http_response_code(404);exit('Resource portal not available');}$access=resource_access($portal);if($method==='POST'&&!$access){verify_csrf();$email=strtolower(trim((string)post('email')));$first=trim((string)post('first_name'));$last=trim((string)post('last_name'));if(!filter_var($email,FILTER_VALIDATE_EMAIL)||$first===''||$last===''){flash('error','Enter your name and a valid email address.');redirect('/resource-library/'.$portal['slug']);}$q=db()->prepare('SELECT id FROM contacts WHERE LOWER(email)=? LIMIT 1');$q->execute([$email]);$contactId=(int)$q->fetchColumn();if(!$contactId){db()->prepare('INSERT INTO contacts(first_name,last_name,email,active) VALUES(?,?,?,1)')->execute([$first,$last,$email]);$contactId=(int)db()->lastInsertId();}else db()->prepare('UPDATE contacts SET first_name=IF(first_name=\'\',?,first_name),last_name=IF(last_name=\'\',?,last_name) WHERE id=?')->execute([$first,$last,$contactId]);resource_apply_tags($contactId,json_decode((string)$portal['fixed_tag_ids'],true)?:[]);$visitorId=null;if(preg_match('/^[a-f0-9-]{36}$/',$_COOKIE['oc_vid']??'')){$q=db()->prepare('SELECT id FROM site_visitors WHERE visitor_key=?');$q->execute([$_COOKIE['oc_vid']]);$visitorId=$q->fetchColumn()?:null;if($visitorId)db()->prepare('UPDATE site_visitors SET contact_id=? WHERE id=?')->execute([$contactId,$visitorId]);}$token=bin2hex(random_bytes(32));db()->prepare('INSERT INTO resource_access_sessions(portal_id,contact_id,access_token,visitor_id,expires_at,last_seen_at) VALUES(?,?,?,?,DATE_ADD(NOW(),INTERVAL 90 DAY),NOW())')->execute([$portal['id'],$contactId,$token,$visitorId]);setcookie('oc_resource_'.$portal['id'],$token,['expires'=>time()+7776000,'path'=>'/','secure'=>true,'httponly'=>true,'samesite'=>'Lax']);audit('register','resource_portal',(int)$portal['id'],['contact_id'=>$contactId]);redirect('/resource-library/'.$portal['slug']);}if(!$access){layout($portal['headline'],function()use($portal){?><div class="card login"><h1><?=e($portal['headline'])?></h1><p><?=nl2br(e($portal['description']))?></p><form method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><div class="form-grid"><label>First name<input name="first_name" required></label><label>Last name<input name="last_name" required></label></div><label>Email<input type="email" name="email" required></label><button>Access resources</button></form></div><?php });exit;}$q=db()->prepare('SELECT r.*,c.name category_name FROM resource_portal_items pi JOIN resources r ON r.id=pi.resource_id LEFT JOIN resource_categories c ON c.id=r.category_id WHERE pi.portal_id=? AND r.active=1 ORDER BY c.position,c.name,pi.position,r.title');$q->execute([$portal['id']]);$items=$q->fetchAll();db()->prepare("INSERT INTO resource_engagements(portal_id,resource_id,contact_id,access_session_id,engagement_type) SELECT ?,r.id,?,?,'view' FROM resource_portal_items pi JOIN resources r ON r.id=pi.resource_id WHERE pi.portal_id=? AND r.active=1")->execute([$portal['id'],$access['contact_id'],$access['id'],$portal['id']]);layout($portal['headline'],function()use($portal,$access,$items){$groups=[];foreach($items as $r)$groups[$r['category_name']?:'Resources'][]=$r;?><div class="actions"><div><h1 style="margin:0"><?=e($portal['headline'])?></h1><p class="muted">Welcome, <?=e($access['first_name'])?></p></div></div><?php if($portal['thank_you_message']):?><div class="card"><?=nl2br(e($portal['thank_you_message']))?></div><?php endif?><?php foreach($groups as $category=>$rows):?><section><h2><?=e($category)?></h2><div class="grid"><?php foreach($rows as $r):?><article class="card resource-card"><h3><?=e($r['title'])?></h3><p><?=nl2br(e($r['description']))?></p><a class="btn" href="/resource-library/<?=e($portal['slug'])?>/<?=$r['id']?>">Access resource</a></article><?php endforeach?></div></section><?php endforeach?><?php });exit;
}
if(preg_match('#^/resource-library/([a-z0-9_-]+)/(\d+)$#',$path,$m)){
 $portal=resource_portal($m[1]);$access=resource_access($portal);if(!$access)redirect('/resource-library/'.$portal['slug']);$q=db()->prepare('SELECT r.* FROM resources r JOIN resource_portal_items pi ON pi.resource_id=r.id WHERE r.id=? AND pi.portal_id=? AND r.active=1');$q->execute([(int)$m[2],$portal['id']]);$r=$q->fetch();if(!$r){http_response_code(404);exit('Resource not found');}resource_apply_tags((int)$access['contact_id'],json_decode((string)$r['tag_ids'],true)?:[]);$kind=$r['resource_type']==='file'?'download':'open';db()->prepare('INSERT INTO resource_engagements(portal_id,resource_id,contact_id,access_session_id,engagement_type) VALUES(?,?,?,?,?)')->execute([$portal['id'],$r['id'],$access['contact_id'],$access['id'],$kind]);if($r['resource_type']==='url')redirect($r['external_url']);if($r['resource_type']==='lead_magnet'){$q=db()->prepare("SELECT public_slug FROM lead_magnets WHERE id=? AND status='published'");$q->execute([$r['lead_magnet_id']]);$slug=$q->fetchColumn();if(!$slug){http_response_code(404);exit('Published resource unavailable');}redirect('/published/lead-magnet/'.$slug.'.pdf');}$file=dirname(__DIR__).'/storage/uploads/resources/'.basename((string)$r['stored_name']);if(!is_file($file)){http_response_code(404);exit('File not found');}header('Content-Type: '.$r['mime_type']);header("Content-Disposition: attachment; filename*=UTF-8''".rawurlencode($r['original_name']));header('X-Content-Type-Options: nosniff');readfile($file);exit;
}

if($path==='/resources'){
 require_permission('resources.view');$portals=db()->query('SELECT p.*,COUNT(DISTINCT a.contact_id) contacts,COUNT(e.id) engagements FROM resource_portals p LEFT JOIN resource_access_sessions a ON a.portal_id=p.id LEFT JOIN resource_engagements e ON e.portal_id=p.id GROUP BY p.id ORDER BY p.updated_at DESC')->fetchAll();$resources=db()->query('SELECT r.*,c.name category_name,COUNT(e.id) engagements FROM resources r LEFT JOIN resource_categories c ON c.id=r.category_id LEFT JOIN resource_engagements e ON e.resource_id=r.id GROUP BY r.id ORDER BY r.updated_at DESC')->fetchAll();layout('Resources Library',function()use($portals,$resources){?><div class="actions"><h1 style="margin:0">Resources Library</h1><span class="spacer"></span><?php if(can('resources.edit')):?><a class="btn secondary" href="/resources/new">Add resource</a><a class="btn" href="/resources/portals/new">Create portal</a><?php endif?></div><div class="card"><h2>Public portals</h2><table><thead><tr><th>Portal</th><th>Public URL</th><th>Contacts</th><th>Engagement</th><th>Status</th></tr></thead><tbody><?php foreach($portals as $p):?><tr><td><a href="/resources/portals/<?=$p['id']?>/edit"><?=e($p['name'])?></a></td><td><a target="_blank" href="/resource-library/<?=e($p['slug'])?>">/resource-library/<?=e($p['slug'])?></a></td><td><?=$p['contacts']?></td><td><?=$p['engagements']?></td><td><?=$p['active']?'Published':'Draft'?></td></tr><?php endforeach?></tbody></table></div><div class="card"><h2>Resources</h2><table><thead><tr><th>Resource</th><th>Category</th><th>Type</th><th>Engagements</th><th>Status</th></tr></thead><tbody><?php foreach($resources as $r):?><tr><td><a href="/resources/<?=$r['id']?>/edit"><?=e($r['title'])?></a></td><td><?=e($r['category_name']?:'Uncategorized')?></td><td><?=e($r['resource_type'])?></td><td><?=$r['engagements']?></td><td><?=$r['active']?'Active':'Archived'?></td></tr><?php endforeach?></tbody></table></div><?php });exit;
}
if($path==='/resources/categories'){
 require_permission('resources.edit');if($method==='POST'){verify_csrf();$action=(string)post('action');if($action==='add')db()->prepare('INSERT INTO resource_categories(name,description,position) VALUES(?,?,?)')->execute([trim((string)post('name')),trim((string)post('description')),(int)post('position')]);elseif($action==='archive')db()->prepare('UPDATE resource_categories SET active=0 WHERE id=?')->execute([(int)post('category_id')]);audit($action,'resource_category',(int)post('category_id'));flash('success','Resource categories updated.');redirect('/resources/categories');}$rows=db()->query('SELECT c.*,COUNT(r.id) resources FROM resource_categories c LEFT JOIN resources r ON r.category_id=c.id GROUP BY c.id ORDER BY c.position,c.name')->fetchAll();layout('Resource categories',function()use($rows){?><div class="actions"><h1 style="margin:0">Resource categories</h1><span class="spacer"></span><a class="btn secondary" href="/resources">Back to resources</a></div><form class="card form-grid" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="add"><label>Name<input name="name" required></label><label>Description<input name="description"></label><label>Position<input type="number" name="position" value="10"></label><button>Add category</button></form><div class="card"><table><thead><tr><th>Category</th><th>Resources</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?=e($r['name'])?><br><span class="muted"><?=e($r['description'])?></span></td><td><?=$r['resources']?></td><td><?=$r['active']?'Active':'Archived'?></td><td><?php if($r['active']):?><form method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="archive"><input type="hidden" name="category_id" value="<?=$r['id']?>"><button class="danger compact">Archive</button></form><?php endif?></td></tr><?php endforeach?></tbody></table></div><?php });exit;
}
if($path==='/resources/new'||preg_match('#^/resources/(\d+)/edit$#',$path,$m)){
 require_permission('resources.edit');$id=(int)($m[1]??0);$r=null;if($id){$q=db()->prepare('SELECT * FROM resources WHERE id=?');$q->execute([$id]);$r=$q->fetch();if(!$r){http_response_code(404);exit('Resource not found');}}if($method==='POST'){verify_csrf();$type=in_array(post('resource_type'),['file','url','lead_magnet'],true)?post('resource_type'):'url';$stored=$r['stored_name']??null;$original=$r['original_name']??null;$mime=$r['mime_type']??null;if($type==='file'&&isset($_FILES['resource_file'])&&$_FILES['resource_file']['error']===UPLOAD_ERR_OK){$f=$_FILES['resource_file'];if($f['size']>25*1024*1024)throw new RuntimeException('Resource files are limited to 25 MB.');$mime=(new finfo(FILEINFO_MIME_TYPE))->file($f['tmp_name']);$allowed=['application/pdf'=>'pdf','application/vnd.openxmlformats-officedocument.wordprocessingml.document'=>'docx','application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'=>'xlsx','application/vnd.openxmlformats-officedocument.presentationml.presentation'=>'pptx','application/zip'=>'zip','text/plain'=>'txt'];if(!isset($allowed[$mime]))throw new RuntimeException('Unsupported resource file type.');$stored=bin2hex(random_bytes(20)).'.'.$allowed[$mime];$dir=dirname(__DIR__).'/storage/uploads/resources';if(!is_dir($dir))mkdir($dir,0770,true);if(!move_uploaded_file($f['tmp_name'],$dir.'/'.$stored))throw new RuntimeException('Upload failed.');$original=mb_substr(basename($f['name']),0,255);} $vals=[post('category_id')?:null,trim((string)post('title')),trim((string)post('description')),$type,$stored,$original,$mime,trim((string)post('external_url'))?:null,post('lead_magnet_id')?:null,json_encode(array_map('intval',(array)post('tags',[]))),post('active')?1:0,user()['id']];if($id){$vals[]=$id;db()->prepare('UPDATE resources SET category_id=?,title=?,description=?,resource_type=?,stored_name=?,original_name=?,mime_type=?,external_url=?,lead_magnet_id=?,tag_ids=?,active=?,updated_by=? WHERE id=?')->execute($vals);}else{db()->prepare('INSERT INTO resources(category_id,title,description,resource_type,stored_name,original_name,mime_type,external_url,lead_magnet_id,tag_ids,active,created_by,updated_by) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?)')->execute(array_merge(array_slice($vals,0,11),[user()['id'],user()['id']]));$id=(int)db()->lastInsertId();}audit($r?'update':'create','resource',$id);flash('success','Resource saved.');redirect('/resources');}$categories=db()->query('SELECT * FROM resource_categories WHERE active=1 ORDER BY position,name')->fetchAll();$magnets=db()->query("SELECT id,title FROM lead_magnets WHERE status='published' ORDER BY title")->fetchAll();layout($r?'Edit resource':'Add resource',function()use($r,$categories,$magnets){?><h1><?=$r?'Edit resource':'Add resource'?></h1><form class="card" method="post" enctype="multipart/form-data"><input type="hidden" name="_csrf" value="<?=csrf()?>"><label>Title<input name="title" value="<?=e($r['title']??'')?>" required></label><label>Description<textarea name="description"><?=e($r['description']??'')?></textarea></label><div class="form-grid"><label>Category<select name="category_id"><option value="">Uncategorized</option><?php foreach($categories as $c):?><option value="<?=$c['id']?>" <?=($r['category_id']??0)==$c['id']?'selected':''?>><?=e($c['name'])?></option><?php endforeach?></select></label><label>Type<select name="resource_type"><option value="file">File upload</option><option value="url" <?=($r['resource_type']??'')==='url'?'selected':''?>>External URL</option><option value="lead_magnet" <?=($r['resource_type']??'')==='lead_magnet'?'selected':''?>>Published lead magnet</option></select></label></div><label>Upload file<input type="file" name="resource_file" accept=".pdf,.docx,.xlsx,.pptx,.zip,.txt"></label><label>External URL<input type="url" name="external_url" value="<?=e($r['external_url']??'')?>"></label><label>Lead magnet<select name="lead_magnet_id"><option value="">None</option><?php foreach($magnets as $lm):?><option value="<?=$lm['id']?>" <?=($r['lead_magnet_id']??0)==$lm['id']?'selected':''?>><?=e($lm['title'])?></option><?php endforeach?></select></label><div><span class="muted">Tags applied when accessed</span><div class="checkboxes"><?php $selected=json_decode((string)($r['tag_ids']??'[]'),true)?:[];foreach(all_tags() as $t):?><label><input type="checkbox" name="tags[]" value="<?=$t['id']?>" <?=in_array($t['id'],$selected)?'checked':''?>><?=e($t['name'])?></label><?php endforeach?></div></div><label><input type="checkbox" name="active" value="1" style="width:auto" <?=($r['active']??true)?'checked':''?>> Active</label><button>Save resource</button></form><?php });exit;
}
if($path==='/resources/portals/new'||preg_match('#^/resources/portals/(\d+)/edit$#',$path,$m)){
 require_permission('resources.edit');$id=(int)($m[1]??0);$p=null;if($id){$q=db()->prepare('SELECT * FROM resource_portals WHERE id=?');$q->execute([$id]);$p=$q->fetch();if(!$p){http_response_code(404);exit('Portal not found');}}if($method==='POST'){verify_csrf();$slug=trim(strtolower(preg_replace('/[^a-z0-9_-]+/i','-',(string)post('slug'))),'-');$vals=[trim((string)post('name')),$slug,trim((string)post('headline')),trim((string)post('description')),trim((string)post('thank_you_message')),json_encode(array_map('intval',(array)post('tags',[]))),post('active')?1:0,user()['id']];if($id){$vals[]=$id;db()->prepare('UPDATE resource_portals SET name=?,slug=?,headline=?,description=?,thank_you_message=?,fixed_tag_ids=?,active=?,updated_by=? WHERE id=?')->execute($vals);}else{db()->prepare('INSERT INTO resource_portals(name,slug,headline,description,thank_you_message,fixed_tag_ids,active,created_by,updated_by) VALUES(?,?,?,?,?,?,?,?,?)')->execute(array_merge(array_slice($vals,0,7),[user()['id'],user()['id']]));$id=(int)db()->lastInsertId();}db()->prepare('DELETE FROM resource_portal_items WHERE portal_id=?')->execute([$id]);$ins=db()->prepare('INSERT INTO resource_portal_items(portal_id,resource_id,position) VALUES(?,?,?)');foreach((array)post('resources',[]) as $pos=>$rid)$ins->execute([$id,(int)$rid,$pos*10]);audit($p?'update':'create','resource_portal',$id);flash('success','Resource portal saved.');redirect('/resources');}$resources=db()->query('SELECT id,title FROM resources WHERE active=1 ORDER BY title')->fetchAll();$selected=[];if($id){$q=db()->prepare('SELECT resource_id FROM resource_portal_items WHERE portal_id=? ORDER BY position');$q->execute([$id]);$selected=$q->fetchAll(PDO::FETCH_COLUMN);}layout($p?'Edit resource portal':'Create resource portal',function()use($p,$resources,$selected){?><h1><?=$p?'Edit resource portal':'Create resource portal'?></h1><form class="card" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><div class="form-grid"><label>Name<input name="name" value="<?=e($p['name']??'')?>" required></label><label>URL code<input name="slug" value="<?=e($p['slug']??'')?>" required></label></div><label>Headline<input name="headline" value="<?=e($p['headline']??'')?>" required></label><label>Description<textarea name="description"><?=e($p['description']??'')?></textarea></label><label>Message after registration<textarea name="thank_you_message"><?=e($p['thank_you_message']??'')?></textarea></label><div><span class="muted">Tags applied at registration</span><div class="checkboxes"><?php $fixed=json_decode((string)($p['fixed_tag_ids']??'[]'),true)?:[];foreach(all_tags() as $t):?><label><input type="checkbox" name="tags[]" value="<?=$t['id']?>" <?=in_array($t['id'],$fixed)?'checked':''?>><?=e($t['name'])?></label><?php endforeach?></div></div><div><span class="muted">Available resources</span><div class="checkboxes"><?php foreach($resources as $r):?><label><input type="checkbox" name="resources[]" value="<?=$r['id']?>" <?=in_array($r['id'],$selected)?'checked':''?>><?=e($r['title'])?></label><?php endforeach?></div></div><label><input type="checkbox" name="active" value="1" style="width:auto" <?=($p['active']??false)?'checked':''?>> Publish portal</label><button>Save portal</button></form><?php });exit;
